template.css_template:
#{{ID}} .utk-container.v2 {
    position: absolute; bottom: 0; left: 0; width: var(--v-width, 100%); min-height: var(--v-height, 60px);
    background: {{PRIMARY_BG}}; display: flex; align-items: stretch; overflow: hidden;
    border: {{BORDER_WIDTH}}px solid {{BORDER_COLOR}}; border-radius: {{BORDER_RADIUS}}px; box-sizing: border-box;
    font-family: '{{FONT_FAMILY}}', sans-serif; opacity: 0; transform: {{ANIMATION_TRANSFORM}}; transform-origin: center; box-shadow: {{BOX_SHADOW}};
}
#{{ID}} .utk-wiper {
    position: absolute; left: 0; top: 0; bottom: 0; min-width: 150px; padding: 0 40px;
    background: {{WIPER_BG}}; display: flex; align-items: center; justify-content: center;
    box-shadow: 5px 0 15px rgba(0,0,0,0.5); border-radius: {{BORDER_RADIUS}}px; z-index: 100; box-sizing: border-box; flex-shrink: 0; overflow: hidden;
}

#{{ID}} .utk-wiper-gleam {
    position: absolute; top: 50%; left: -100%; width: {{WIPER_GLEAM_WIDTH}}%; height: {{WIPER_GLEAM_HEIGHT}}px; display: {{#if WIPER_GLEAM_ENABLED}}block{{else}}none{{/if}};
    background: {{WIPER_GLEAM_BG}}; transform: translateY(-50%) skewX(-20deg); pointer-events: none;
    animation: utk-gleam-v2 {{WIPER_GLEAM_DURATION}}s infinite ease-in-out;
}
#{{ID}} .utk-wiper-text {
    font-weight: {{WIPER_FONT_WEIGHT}}; font-size: {{WIPER_FONT_SIZE}}px; font-family: {{WIPER_FONT}}, sans-serif;
    color: {{WIPER_TEXT_COLOR}}; letter-spacing: {{WIPER_LETTER_SPACING}}px; position: relative; z-index: 101; white-space: nowrap;
}
#{{ID}} .utk-panel-horizontal, #{{ID}} .utk-panel-single {
    flex: 1; position: relative; overflow: hidden;
}
#{{ID}} .utk-track {
    display: flex; align-items: center; white-space: nowrap; padding-left: 100%; flex: 1; height: 100%;
}
#{{ID}} .utk-item {
    color: {{TITLE_COLOR}}; font-size: {{TITLE_SIZE}}px; font-weight: {{TITLE_WEIGHT}};
    text-transform: {{TITLE_TRANSFORM}}; padding-left: 20px; padding-right: 20px; padding-top: {{PADDING_Y}}px; padding-bottom: {{PADDING_Y}}px; white-space: nowrap; display: block; box-sizing: border-box; line-height: 1;
}
#{{ID}} .utk-sep { {{SEPARATOR_CSS}} align-self: center; }
#{{ID}} .utk-msg-box {
    width: auto; position: absolute; left: 0; top: 50%; transform: translateY(-50%); display: block;
    padding-left: 20px; padding-right: 20px; padding-top: {{PADDING_Y}}px; padding-bottom: {{PADDING_Y}}px; box-sizing: border-box; color: {{TITLE_COLOR}}; font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}}; text-transform: {{TITLE_TRANSFORM}}; white-space: nowrap; font-family: '{{FONT_FAMILY}}', sans-serif;
    opacity: 0; transition: opacity 0.4s ease-in-out, padding-left 0.4s ease-in-out, font-size 0.4s ease-in-out; line-height: 1; z-index: 1;
}
#{{ID}} .utk-msg-box.visible { opacity: 1; }
#{{ID}} .utk-wiper.mode-whip-right { animation: utk-slide-right-v2 1s linear forwards; }
#{{ID}} .utk-wiper.mode-whip-back { animation: utk-slide-back-v2 0.5s ease-in-out forwards; }
@keyframes utk-slide-right-v2 { 0% { left: 0%; } 100% { left: calc(100% - var(--wiper-w, 150px)); } }
@keyframes utk-slide-back-v2 { 0% { left: calc(100% - var(--wiper-w, 150px)); } 100% { left: 0%; } }
@keyframes utk-gleam-v2 { 0% { left: -{{WIPER_GLEAM_WIDTH}}%; } 100% { left: 200%; } }

template.js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container   = root.querySelector('.utk-container');
    const wiper       = root.querySelector('.utk-wiper');
    const wiperText   = root.querySelector('.utk-wiper-text');
    const panelHoriz  = root.querySelector('.utk-panel-horizontal');
    const panelSingle = root.querySelector('.utk-panel-single');
    const msgBox      = root.querySelector('.utk-msg-box');
    const track       = root.querySelector('.utk-track');
    const dataEl      = root.querySelector('#f-news-list');

    if (!container || !dataEl) return;

    const MODE = ("{{TICKER_MODE}}" || "whip").trim();
    const DEFAULT_WIPER = "{{WIPER_TEXT}}";
    const WIPER_SHOW = "{{WIPER_SHOW}}" !== "false";
    if (wiper && !WIPER_SHOW) wiper.style.display = 'none';
    const TICKER_SPEED_VAL = parseFloat("{{TICKER_SPEED}}") || 5;

    let items = [];
    const b64 = dataEl.getAttribute('data-b64');
    if (b64) {
        try { items = JSON.parse(decodeURIComponent(escape(atob(b64 + "=".repeat((4 - b64.length % 4) % 4))))); } 
        catch(e) { try { items = JSON.parse(dataEl.textContent || '[]'); } catch(err) { items = []; } }
    }
    if (!items.length) items = ['BRAK WIADOMOŚCI'];

    const getText = (item) => (typeof item === 'object') ? (item.text || '') : String(item);
    const getCat  = (item) => (typeof item === 'object') ? (item.category || '') : '';

    let currentIndex = 0;
    let cycleRunning = false;
    let activeTimeouts = [];

    function updateWiperUI(labelText) {
        const label = (labelText || DEFAULT_WIPER).trim();
        const show = WIPER_SHOW && !!label;
        if (!wiper) return 0;
        gsap.killTweensOf(wiper);
        if (!show) {
            if (wiper.style.display !== 'none') {
                gsap.to(wiper, {
                    width: 0, minWidth: 0, opacity: 0, duration: 0.3, ease: 'power2.in',
                    onUpdate: () => container.style.setProperty('--wiper-w', wiper.offsetWidth + 'px'),
                    onComplete: () => {
                        wiper.style.display = 'none';
                        gsap.set(wiper, { clearProps: 'width,minWidth,opacity' });
                        container.style.setProperty('--wiper-w', '0px');
                    }
                });
            }
            return 0;
        }
        if (wiperText) wiperText.innerText = label;
        if (wiper.style.display === 'none') {
            wiper.style.display = 'flex';
            const naturalW = wiper.offsetWidth;
            gsap.fromTo(wiper,
                { width: 0, minWidth: 0, opacity: 0 },
                { width: naturalW, minWidth: naturalW, opacity: 1, duration: 0.4, ease: 'power2.out',
                  onUpdate: () => container.style.setProperty('--wiper-w', wiper.offsetWidth + 'px'),
                  onComplete: () => { gsap.set(wiper, { clearProps: 'width,minWidth,opacity' }); container.style.setProperty('--wiper-w', wiper.offsetWidth + 'px'); }
                }
            );
            return naturalW;
        } else {
            const currentW = wiper.offsetWidth;
            gsap.fromTo(wiper, { width: currentW }, {
                width: 'auto', duration: 0.35, ease: 'power2.inOut',
                onUpdate: () => container.style.setProperty('--wiper-w', wiper.offsetWidth + 'px'),
                onComplete: () => { gsap.set(wiper, { clearProps: 'width' }); container.style.setProperty('--wiper-w', wiper.offsetWidth + 'px'); }
            });
            return currentW;
        }
    }

    function adjustFont(el, wiperW) {
        const base = parseFloat("{{TITLE_SIZE}}") || 40;
        const pl = wiperW > 0 ? (wiperW + 20) : 20;

        const oldTransition = el.style.transition;
        el.style.transition = 'none';
        el.style.fontSize = base + 'px';
        el.style.paddingLeft = pl + 'px';

        const maxW = container.offsetWidth - pl - 20;
        const contentW = el.scrollWidth - pl - 20;

        if (maxW > 10 && contentW > maxW) {
            const newSize = (maxW / contentW) * base;
            el.style.fontSize = Math.min(newSize, base) + 'px';
        }

        void el.offsetHeight;
        el.style.transition = oldTransition;
    }

    // WHIP / VERTICAL
    function runSingle() {
        if (!cycleRunning) return;
        msgBox.classList.remove('visible');

        const item = items[currentIndex];
        const wW = updateWiperUI(getCat(item));
        msgBox.innerHTML = getText(item);
        adjustFont(msgBox, wW);

        activeTimeouts.push(setTimeout(() => {
            if (!cycleRunning) return;
            msgBox.classList.add('visible');
        }, 100));

        const displayMs = MODE === 'whip' ? 4000 : (TICKER_SPEED_VAL * 1000);

        activeTimeouts.push(setTimeout(() => {
            if (!cycleRunning) return;
            msgBox.classList.remove('visible');

            if (MODE === 'whip') {
                activeTimeouts.push(setTimeout(() => {
                    if (!cycleRunning) return;
                    if (wiper && wiper.style.display !== 'none') {
                        wiper.classList.remove('mode-whip-back');
                        wiper.classList.add('mode-whip-right');
                    }
                    activeTimeouts.push(setTimeout(() => {
                        if (!cycleRunning) return;
                        if (wiper && wiper.style.display !== 'none') {
                            wiper.classList.remove('mode-whip-right');
                            wiper.classList.add('mode-whip-back');
                        }
                        activeTimeouts.push(setTimeout(() => {
                            if (!cycleRunning) return;
                            currentIndex = (currentIndex + 1) % items.length;
                            runSingle();
                        }, 500));
                    }, 1000));
                }, 400));
            } else {
                activeTimeouts.push(setTimeout(() => {
                    if (!cycleRunning) return;
                    currentIndex = (currentIndex + 1) % items.length;
                    runSingle();
                }, 500));
            }
        }, displayMs));
    }

    // HORIZONTAL
    function runHorizontal() {
        if (!track) return;
        const initialCat = getCat(items[0]);
        updateWiperUI(initialCat);
        const trackItems = Array.from(track.querySelectorAll('.utk-item'));
        const itemData = trackItems.map((el, idx) => ({
            el, 
            offset: el.offsetLeft, 
            category: getCat(items[idx]) || DEFAULT_WIPER
        }));

        const fullWidth = track.scrollWidth || 0;
        const speed = (TICKER_SPEED_VAL > 10) ? TICKER_SPEED_VAL : (TICKER_SPEED_VAL * 50);
        const duration = fullWidth / speed;

        gsap.to(track, {
            x: -fullWidth,
            duration: duration,
            ease: 'none', 
            repeat: -1,
            onUpdate: function() {
                const curX = gsap.getProperty(track, 'x');
                let activeCat = DEFAULT_WIPER;
                let currentWiperW = parseFloat(container.style.getPropertyValue('--wiper-w')) || 0;
                const trigger = currentWiperW > 0 ? currentWiperW : 50;
                for (let i = 0; i < itemData.length; i++) {
                    if (curX + itemData[i].offset > trigger) {
                        activeCat = itemData[i].category;
                        break;
                    }
                }
                if (wiperText && wiperText.innerText !== activeCat) {
                    updateWiperUI(activeCat);
                }
            }
        });
    }

    root.__slt_show = () => {
        cycleRunning = true;
        if (MODE === 'horizontal') {
            panelHoriz.style.display = 'block';
            panelSingle.style.display = 'none';
            runHorizontal();
        } else {
            panelHoriz.style.display = 'none';
            panelSingle.style.display = 'block';
            runSingle();
        }

        const animInStr = '{{{ANIMATION_IN_JSON}}}';
        const animIn = (animInStr && animInStr !== '') ? JSON.parse(animInStr) : {};
        const duration = typeof animIn.duration !== 'undefined' ? parseFloat(animIn.duration) : 0.6;
        const delay = typeof animIn.delay !== 'undefined' ? parseFloat(animIn.delay) : 0;

        let ease = 'power2.out';
        if (animIn.ease === 'linear') ease = 'none';
        else if (animIn.ease === 'ease-in') ease = 'power2.in';
        else if (animIn.ease === 'ease-in-out') ease = 'power2.inOut';
        else if (animIn.ease === 'back') ease = 'back.out(1.7)';
        else if (animIn.ease === 'elastic') ease = 'elastic.out(1, 0.3)';
        else if (animIn.ease === 'bounce') ease = 'bounce.out';

        const tl = gsap.timeline();
        tl.to(container, { opacity: 1, x: 0, y: 0, scale: 1, scaleX: 1, scaleY: 1, duration: duration, delay: delay, ease: ease });
        return tl;
    };

    root.__slt_hide = () => {
        cycleRunning = false;
        activeTimeouts.forEach(t => clearTimeout(t));
        activeTimeouts = [];
        if (track) gsap.killTweensOf(track);

        const animOutStr = '{{{ANIMATION_OUT_JSON}}}';
        const animOut = (animOutStr && animOutStr !== '') ? JSON.parse(animOutStr) : {};
        const duration = typeof animOut.duration !== 'undefined' ? parseFloat(animOut.duration) : 0.4;
        const delay = typeof animOut.delay !== 'undefined' ? parseFloat(animOut.delay) : 0;

        let ease = 'power2.in';
        if (animOut.ease === 'linear') ease = 'none';
        else if (animOut.ease === 'ease-out') ease = 'power2.out';
        else if (animOut.ease === 'ease-in-out') ease = 'power2.inOut';
        else if (animOut.ease === 'back') ease = 'back.in(1.7)';

        let targetProps = { opacity: 0, duration: duration, delay: delay, ease: ease };
        if (animOut.type === 'slide') {
            if (animOut.direction === 'top') targetProps.y = -100;
            else if (animOut.direction === 'bottom') targetProps.y = 100;
            else if (animOut.direction === 'left') targetProps.x = -100;
            else if (animOut.direction === 'right') targetProps.x = 100;
        } else if (animOut.type === 'scale') {
            targetProps.scale = 0.5;
        }

        const tl = gsap.timeline();
        tl.to(container, targetProps);
        return tl;
    };
})();
